# Query the SOSA ontology for properties related to time
result = sparql_query("""
PREFIX sosa: <http://www.w3.org/ns/sosa/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?prop ?label ?comment WHERE {
  GRAPH <http://localhost:8080/ontology/sosa> {
    ?prop a ?type .
    FILTER(?type IN (owl:ObjectProperty, owl:DatatypeProperty, rdf:Property))
    OPTIONAL { ?prop rdfs:label ?label }
    OPTIONAL { ?prop rdfs:comment ?comment }
    FILTER(CONTAINS(STR(?prop), "Time") || CONTAINS(STR(?prop), "time") || CONTAINS(STR(?prop), "phenomenon"))
  }
}
""")
print(result)

